#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *p = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &p[i]);
        long long nim = 0;
        for (int i = 0; i < N; ++i) {
            long long gap = p[i] - (i + 1);
            nim ^= gap;
        }
        if (nim == 0) {
            printf("Johnny wins\n");
        } else {
            printf("Mary wins\n");
            for (int i = 0; i < N; ++i) {
                long long gap = p[i] - (i + 1);
                long long new_gap = gap ^ nim;
                if (new_gap < gap) {
                    long long new_pos = new_gap + (i + 1);
                    printf("Move %lld to %lld\n", p[i], new_pos);
                    break;
                }
            }
        }
        printf("\n");
        free(p);
    }
    return 0;
}

