import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String line;
            // skip possible blank lines
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            int N = Integer.parseInt(line.trim());
            st = new StringTokenizer(br.readLine());
            long[] p = new long[N];
            for (int i = 0; i < N; ++i) p[i] = Long.parseLong(st.nextToken());
            long nim = 0;
            for (int i = 0; i < N; ++i) nim ^= (p[i] - (i + 1));
            if (nim == 0) {
                out.append("Johnny wins\n");
            } else {
                out.append("Mary wins\n");
                for (int i = 0; i < N; ++i) {
                    long gap = p[i] - (i + 1);
                    long newGap = gap ^ nim;
                    if (newGap < gap) {
                        long newPos = newGap + (i + 1);
                        out.append("Move ").append(p[i]).append(" to ").append(newPos).append('\n');
                        break;
                    }
                }
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

