import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        p = [int(next(it)) for _ in range(N)]
        nim = 0
        for i, pos in enumerate(p, start=1):
            nim ^= (pos - i)
        if nim == 0:
            out_lines.append("Johnny wins")
        else:
            out_lines.append("Mary wins")
            for i, pos in enumerate(p, start=1):
                gap = pos - i
                new_gap = gap ^ nim
                if new_gap < gap:
                    new_pos = new_gap + i
                    out_lines.append(f"Move {pos} to {new_pos}")
                    break
        out_lines.append("")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

